// DisplayNameContainsFold applies the ContainsFold predicate on the "display_name" field.
func DisplayNameContainsFold(v string) predicate.CategoryDefaultFeature {
	return predicate.CategoryDefaultFeature(sql.FieldContainsFold(FieldDisplayName, v))
}

// HasCategory applies the HasEdge predicate on the "category" edge.
func HasCategory() predicate.CategoryDefaultFeature {
	return predicate.CategoryDefaultFeature(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, CategoryTable, CategoryColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasCategoryWith applies the HasEdge predicate on the "category" edge with a given conditions (other predicates).
func HasCategoryWith(preds ...predicate.Category) predicate.CategoryDefaultFeature {
	return predicate.CategoryDefaultFeature(func(s *sql.Selector) {
		step := newCategoryStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasFeature applies the HasEdge predicate on the "feature" edge.
func HasFeature() predicate.CategoryDefaultFeature {
	return predicate.CategoryDefaultFeature(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, FeatureTable, FeatureColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasFeatureWith applies the HasEdge predicate on the "feature" edge with a given conditions (other predicates).
func HasFeatureWith(preds ...predicate.Feature) predicate.CategoryDefaultFeature {
	return predicate.CategoryDefaultFeature(func(s *sql.Selector) {
		step := newFeatureStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.CategoryDefaultFeature) predicate.CategoryDefaultFeature {
	return predicate.CategoryDefaultFeature(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.CategoryDefaultFeature) predicate.CategoryDefaultFeature {
	return predicate.CategoryDefaultFeature(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.CategoryDefaultFeature) predicate.CategoryDefaultFeature {
	return predicate.CategoryDefaultFeature(sql.NotPredicates(p))
}
